name="Prakash"
# Short string
short= name[1:4] # This will print characters from index 1 to 3 (4 is exclusive)
print(short)
char= name[0] # This will print the first character of the string
print(char)
# Negative indexing
last_char= name[-1] # This will print the last character of the string
print(last_char)
short_neg=name[-5:-1] # This will print characters from index -5 to -2 (since -1 is exclusive)
print(short_neg)